&lt;li&gt;🔗 &lt;a class=&#34;link&#34;   href=&#34;https://www.linuxmi.com/2022-10-top-linux.html&#34; &gt;https://www.linuxmi.com/2022-10-top-linux.html &lt;i class=&#34;fa-regular fa-arrow-up-right-from-square fa-sm&#34;&gt;&lt;/i&gt;&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;

    &lt;/div&gt;
  &lt;/div&gt;
